/*Table structure for table `fa_transaction_details` */

DROP TABLE IF EXISTS `fa_transaction_details`;

CREATE TABLE `fa_transaction_details` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `reconcile` tinyint(1) DEFAULT 0,
  `against` text DEFAULT NULL,
  `reconcile_date` date DEFAULT NULL,
  `transaction` bigint(20) NOT NULL DEFAULT 0,
  `voucher_dates` date NOT NULL DEFAULT '2024-01-01',
  `voucher_types` int(11) NOT NULL DEFAULT 0,
  `location` int(10) NOT NULL,
  `activity` int(11) NOT NULL,
  `head` int(20) NOT NULL,
  `sub_head` int(20) NOT NULL,
  `bank_ref_type` varchar(30) DEFAULT NULL,
  `cheque_no` varchar(100) DEFAULT 'DFT092024',
  `debit` decimal(20,3) NOT NULL,
  `credit` decimal(20,3) NOT NULL,
  `region` int(10) DEFAULT NULL,
  `debit_sdr` decimal(20,3) DEFAULT 0.000,
  `credit_sdr` decimal(20,3) DEFAULT 0.000,
  `bank_trans_journal` varchar(50) DEFAULT NULL,
  `currency` int(11) DEFAULT 1,
  `rate` decimal(12,3) DEFAULT 0.000,
  `ref_no` varchar(60) DEFAULT NULL,
  `type` tinyint(4) DEFAULT NULL,
  `against_status` int(11) DEFAULT NULL COMMENT 'received partial/more than the voucher amount-from against ID',
  `status` int(11) DEFAULT NULL,
  `author` bigint(20) NOT NULL,
  `created` datetime NOT NULL,
  `modified` datetime NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8;

/*Data for the table `fa_transaction_details` */


