  `modified_by` varchar(255) DEFAULT NULL,
  `author` int(11) DEFAULT NULL,
  `modified_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8;

