DELIMITER $$

/*!50003 DROP TRIGGER*//*!50032 IF EXISTS */ /*!50003 `fa_transaction_details_after_delete` */$$

/*!50003 CREATE */ /*!50017 DEFINER = 'root'@'localhost' */ /*!50003 TRIGGER `fa_transaction_details_after_delete` AFTER DELETE ON `fa_transaction_details` FOR EACH ROW 
BEGIN
  VALUES (
    'DELETE',
    OLD.id,
    JSON_OBJECT(
      'location', OLD.location,
      'head', OLD.head,
      'sub_head', OLD.sub_head,
      'debit', OLD.debit,
      'credit', OLD.credit,
      'ref_no', OLD.ref_no,
      'cheque_no', OLD.cheque_no,
      'author', OLD.author
    ),
    CURRENT_USER(),
    OLD.author
  );
END */$$


