/* Trigger structure for table `sys_users` */

DELIMITER $$

/*!50003 DROP TRIGGER*//*!50032 IF EXISTS */ /*!50003 `trigger_login_update` */$$

/*!50003 CREATE */ /*!50017 DEFINER = 'root'@'localhost' */ /*!50003 TRIGGER `trigger_login_update` AFTER UPDATE ON `sys_users` FOR EACH ROW CASE WHEN NOT NEW.last_login = OLD.last_login THEN
	VALUES (
                       NULL,
	    NEW.last_accessed_ip,
	    NEW.id,
	    NEW.last_login,
	    NULL
	);
    WHEN NOT NEW.last_logout = OLD.last_logout THEN
        UPDATE `logins` SET
	  modified = NEW.last_logout
          WHERE
	  author = NEW.id AND created = OLD.last_login;
    ELSE
        DELETE FROM `logins` WHERE author = 0;
END CASE */$$


